CREATE OR REPLACE FUNCTION bump_data_freshness_imported_gps_track_trigger()
RETURNS TRIGGER AS $$
BEGIN
  IF TG_OP = 'DELETE' THEN
    IF OLD.track_source = 'PLANNED' THEN
      RETURN OLD;
    END IF;
    PERFORM bump_data_freshness('tracks');
    RETURN OLD;
  END IF;

  IF TG_OP = 'UPDATE' AND OLD.track_source = 'PLANNED' AND NEW.track_source = 'PLANNED' THEN
    RETURN NEW;
  END IF;

  IF TG_OP = 'INSERT' AND NEW.track_source = 'PLANNED' THEN
    RETURN NEW;
  END IF;

  PERFORM bump_data_freshness('tracks');
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION bump_data_freshness_imported_gps_track_data_trigger()
RETURNS TRIGGER AS $$
DECLARE
  should_bump boolean;
BEGIN
  IF TG_OP = 'INSERT' THEN
    SELECT EXISTS (
      SELECT 1 FROM gps_track gt
       WHERE gt.id = NEW.gps_track_id
         AND gt.track_source <> 'PLANNED'
    ) INTO should_bump;
  ELSIF TG_OP = 'UPDATE' THEN
    SELECT EXISTS (
      SELECT 1 FROM gps_track gt
       WHERE gt.id IN (OLD.gps_track_id, NEW.gps_track_id)
         AND gt.track_source <> 'PLANNED'
    ) INTO should_bump;
  ELSE
    SELECT EXISTS (
      SELECT 1 FROM gps_track gt
       WHERE gt.id = OLD.gps_track_id
         AND gt.track_source <> 'PLANNED'
    ) INTO should_bump;
  END IF;

  IF should_bump THEN
    PERFORM bump_data_freshness('track_geometry');
  END IF;

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;
